content.text:
/* Type selector — matches every <p> element */
p { color: #374151; }

/* Class selector — matches any element with class="card" */
.card { border-radius: 8px; padding: 16px; }

/* ID selector — matches the one element with id="hero" */
#hero { font-size: 2rem; }

/* Universal selector — matches every element */
* { box-sizing: border-box; }

/* Style all external links */
a[href^="https://"] { color: #3b82f6; }

/* Style PDF links */
a[href$=".pdf"]::after { content: " (PDF)"; font-size: 0.8em; }

/* Style required inputs */
input[required] { border-left: 3px solid #ef4444; }

/* Style disabled buttons */
button[disabled] { opacity: 0.5; cursor: not-allowed; }

/* Descendant — any <span> inside .card, at any nesting depth */
.card span { font-style: italic; }

/* Child — only <li> that are direct children of <ul> */
ul > li { list-style: disc; }

/* Adjacent sibling — <p> that immediately follows an <h2> */
h2 + p { margin-top: 0; }

/* General sibling — all <p> that follow an <h2> and share its parent */
h2 ~ p { color: #6b7280; }

/* Group — apply same rule to multiple selectors */
h1, h2, h3 { font-family: 'Inter', sans-serif; }

a:hover  { text-decoration: underline; }
a:focus  { outline: 2px solid #3b82f6; outline-offset: 2px; }
a:active { color: #1d4ed8; }

/* :focus-visible — shows focus ring only on keyboard navigation, not mouse click */
button:focus-visible { outline: 2px solid #3b82f6; }

/* :focus-within — parent gets style when any child has focus */
.form-group:focus-within { border-color: #3b82f6; }

/* First and last child */
li:first-child { font-weight: bold; }
li:last-child  { border-bottom: none; }

/* nth-child — every even row */
tr:nth-child(even) { background: #f8fafc; }

/* nth-child with formula — every 3rd item starting from 1 */
li:nth-child(3n+1) { color: #3b82f6; }

/* :only-child — child with no siblings */
li:only-child { display: none; }

/* :nth-of-type — ignores element type mix */
p:nth-of-type(2) { font-size: 1.1rem; }

/* :not() — elements that don't match */
li:not(:last-child) { border-bottom: 1px solid #e2e8f0; }

/* :is() — matches any in the list; forgiving (invalid selectors are ignored) */
:is(h1, h2, h3) { line-height: 1.25; }

/* :where() — same as :is() but contributes zero specificity */
:where(article, section) p { max-width: 65ch; }

/* :has() — parent selector (CSS Selectors Level 4, 2023) */
label:has(+ input:required)::after { content: " *"; color: #ef4444; }
form:has(:invalid) button[type="submit"] { opacity: 0.5; }

/* ::before / ::after — generated content via content property */
.required-label::after {
  content: " *";
  color: #ef4444;
  font-size: 0.875rem;
}

/* ::placeholder — style placeholder text */
input::placeholder { color: #9ca3af; font-style: italic; }

/* ::selection — style text the user has highlighted */
::selection { background: #3b82f6; color: white; }

/* ::first-line — only the first rendered line */
p::first-line { font-variant: small-caps; }

/* ::marker — list item bullet or number */
li::marker { color: #3b82f6; font-size: 1.2rem; }

/* Specificity: 0,0,1,1 (.btn + a) */
a.btn { color: white; }

/* Specificity: 0,0,2,1 (.nav + .active + a) — this wins */
.nav .active a { color: yellow; }

/* !important — overrides all specificity (use sparingly) */
a { color: blue !important; }

import { Component, ViewEncapsulation } from '@angular/core';

@Component({
  selector: 'app-card',
  templateUrl: './card.component.html',
  styleUrl: './card.component.css',
  // Default — styles are scoped to this component
  encapsulation: ViewEncapsulation.Emulated,  // default

  // Alternative: global styles (use for themes, not component styles)
  // encapsulation: ViewEncapsulation.None,

  // Shadow DOM native encapsulation (limited browser support for styling)
  // encapsulation: ViewEncapsulation.ShadowDom,
})
export class CardComponent {}

/* card.component.css */

/* :host — targets the <app-card> element itself */
:host {
  display: block;       /* components are inline by default */
  border-radius: 8px;
  overflow: hidden;
}

/* :host with class — when the host element has .featured class */
:host(.featured) {
  border: 2px solid #3b82f6;
}

/* :host-context — ancestors control the component's appearance */
:host-context(.dark-theme) {
  background: #1e293b;
  color: #e2e8f0;
}

/* Use :host to limit the scope — without :host the rule becomes global */
:host ::ng-deep .mat-button {
  border-radius: 20px;
}

/* Declare layer order — later layers win for equal specificity */
@layer reset, base, components, utilities;

/* Assign styles to layers */
@layer reset {
  *, *::before, *::after { box-sizing: border-box; margin: 0; }
}

@layer base {
  p { color: #374151; line-height: 1.6; }
}

@layer components {
  .btn { padding: 0.5rem 1rem; border-radius: 4px; }
}

/* Utilities always win (declared last) */
@layer utilities {
  .text-center { text-align: center !important; }
}

/* login.component.css */
.field { display: flex; flex-direction: column; gap: 4px; }

/* :focus-within highlights the entire field group on focus */
.field:focus-within label { color: #3b82f6; }

/* Attribute selector on aria-invalid drives error state */
input[aria-invalid="true"] {
  border-color: #ef4444;
  background: #fef2f2;
}

/* Show error span only when input is invalid */
input[aria-invalid="true"] + span.error { display: block; color: #ef4444; }
.error { display: none; }

/* :has() alternative — style .field when child input is invalid */
.field:has(input[aria-invalid="true"]) label { color: #ef4444; }
